package migrate_test

import (
	"database/sql"
	"testing"

	"github.com/oklog/ulid/v2"
	"github.com/stretchr/testify/require"
)

func TestMyDataMigration(t *testing.T) {
	rowID := ulid.Make().String()

	runner{
		stops: stops{
			{
				// Insert test data BEFORE the migration runs
				version:   20260320084936, // last version before your migration
				direction: directionUp,
				action: func(t *testing.T, db *sql.DB) {
					_, err := db.Exec(`INSERT INTO my_table (id, namespace, created_at, updated_at, name) VALUES ($1, 'default', NOW(), NOW(), 'test')`, rowID)
					require.NoError(t, err)
				},
			},
			{
				// Verify migration results AFTER the migration
				version:   20260320171954, // your migration version
				direction: directionUp,
				action: func(t *testing.T, db *sql.DB) {
					var newCol sql.NullString
					err := db.QueryRow(`SELECT new_column FROM my_table WHERE id = $1`, rowID).Scan(&newCol)
					require.NoError(t, err)
					require.True(t, newCol.Valid)
					require.Equal(t, "expected_value", newCol.String)
				},
			},
		},
	}.Test(t)
}
